import{_ as a,o as i,c as t,a3 as s}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Communication Templates — Deployment","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Communication Templates — Deployment | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/communication-templates"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Communication Templates — Deployment | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/communication-templates"}]]},"headers":[],"relativePath":"deployment/communication-templates.md","filePath":"deployment/communication-templates.md","lastUpdated":1784403917000}'),o={name:"deployment/communication-templates.md"};function n(l,e,r,d,p,c){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="communication-templates-—-deployment" tabindex="-1">Communication Templates — Deployment <a class="header-anchor" href="#communication-templates-—-deployment" aria-label="Permalink to &quot;Communication Templates — Deployment&quot;">​</a></h1><h2 id="production-deploy-migrate-only" tabindex="-1">Production deploy (migrate-only) <a class="header-anchor" href="#production-deploy-migrate-only" aria-label="Permalink to &quot;Production deploy (migrate-only)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize</span></span></code></pre></div><p>This ships:</p><ol><li>Schema for <code>communication_templates</code></li><li>Catalog row + workspace entitlements for <code>communication-templates</code> (data migration)</li><li>Additive permission grants for default roles (data migration)</li></ol><p>Do <strong>not</strong> run <code>db:seed</code>, <code>CatalogSeeder</code>, or any permission seeder in production for this module.</p><h2 id="what-the-data-migrations-do-and-do-not-do" tabindex="-1">What the data migrations do (and do not do) <a class="header-anchor" href="#what-the-data-migrations-do-and-do-not-do" aria-label="Permalink to &quot;What the data migrations do (and do not do)&quot;">​</a></h2><h3 id="register-communication-templates-module" tabindex="-1"><code>register_communication_templates_module</code> <a class="header-anchor" href="#register-communication-templates-module" aria-label="Permalink to &quot;`register_communication_templates_module`&quot;">​</a></h3><p>Uses <code>App\\Support\\Catalog\\DefaultModuleRegistrar</code>:</p><ul><li>Inserts the CRM category if missing</li><li>Inserts the <code>communication-templates</code> module <strong>only if the slug is missing</strong></li><li>Never overwrites commercial flags, prices, or renamed catalog fields</li><li>Installs an included subscription <strong>only</strong> for workspaces that have never had a subscription row for that module (including soft-deleted rows)</li><li>Does <strong>not</strong> reactivate cancelled, suspended, or soft-deleted subscriptions</li><li>Clears entitlement cache only for workspaces that received a new install</li></ul><h3 id="add-communication-template-permissions" tabindex="-1"><code>add_communication_template_permissions</code> <a class="header-anchor" href="#add-communication-template-permissions" aria-label="Permalink to &quot;`add_communication_template_permissions`&quot;">​</a></h3><p>Uses <code>App\\Support\\Permissions\\TenantPermissionSynchronizer</code>:</p><ul><li>Creates missing <code>communication-templates.*</code> permission vocabulary rows</li><li>Grants only those permissions to default roles that should have them</li><li>Never runs <code>syncPermissions()</code> on existing roles</li><li>Never removes customized role permissions</li><li>Idempotent: re-running creates zero duplicates</li></ul><h2 id="new-workspaces" tabindex="-1">New workspaces <a class="header-anchor" href="#new-workspaces" aria-label="Permalink to &quot;New workspaces&quot;">​</a></h2><p><code>TenantProvisioningService</code> (before owner creation):</p><ol><li><code>ModuleSubscriptionService::installDefaultModules()</code> — every published <code>is_default_included</code> module</li><li><code>TenantAuthorizationProvisioningService::provisionDefaults()</code> — workspace roles + default permission maps</li></ol><p>Login / dashboard / role listing never provision or repair RBAC.</p><h2 id="future-modules" tabindex="-1">Future modules <a class="header-anchor" href="#future-modules" aria-label="Permalink to &quot;Future modules&quot;">​</a></h2><p>Copy this pattern for each new default-included module:</p><ol><li>Schema migration(s) for domain tables</li><li>Data migration using <code>DefaultModuleRegistrar</code></li><li>Data migration using <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code></li><li>Keep <code>CatalogSeeder</code> in sync for <strong>fresh local/CI databases only</strong></li></ol><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --compact</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/Feature/ProductionModuleDeploymentTest.php</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --compact</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/Feature/Tenant/CommunicationTemplates</span></span></code></pre></div><p>Frontend (optional):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SaaS-Frontend</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:e2e:communication-templates</span></span></code></pre></div><p>Smoke after deploy:</p><ol><li>Existing workspace sees <strong>Templates</strong> in nav (module installed + permissions granted)</li><li>Lead detail shows WhatsApp when phone is present</li><li>Marketplace/commercial flags for other modules remain unchanged</li><li>A customized staff role that had permissions removed does <strong>not</strong> regain revoked permissions (only the listed new grants are added)</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/deployment/platform-production-runbook">Platform production runbook</a></li><li><a href="/deployment/module-development">Module development — production</a></li><li><a href="/developer-guide/communication-templates">Developer guide</a></li></ul>',28)])])}const u=a(o,[["render",n]]);export{h as __pageData,u as default};
